import React, { useState } from "react";
import {
  Button,
  TextField,
  Typography,
  Box,
  Grid,
} from "@mui/material";
import { uploadRiderDocs } from "../../services/api";
import { useNavigate } from "react-router-dom";

export default function DocumentUpload() {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    licenseNumber: "",
    rcNumber: "",
    insuranceNumber: "",
    photoUrl: "",
    licenseImage: null,
    rcImage: null,
    insuranceImage: null,
    aadharFront: null,
    aadharBack: null,
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.files[0] });
  };

  const handleSubmit = async () => {
    const token = localStorage.getItem("token");
    const formData = new FormData();
    Object.entries(form).forEach(([key, value]) => {
      formData.append(key, value);
    });

    try {
      await uploadRiderDocs(token, formData);
      alert("Documents uploaded successfully! Pending admin approval.");
      navigate("/rider-dashboard");
    } catch (err) {
      console.error("Upload error:", err);
      alert("Failed to upload documents.");
    }
  };

  return (
    <Box sx={{ maxWidth: 800, mx: "auto", mt: 5, p: 3 }}>
      <Typography
        variant="h4"
        align="center"
        sx={{ fontWeight: "bold", mb: 4 }}
      >
        Upload Documents
      </Typography>

      {/* License */}
      <Grid container spacing={2} alignItems="center" sx={{ mb: 2 }}>
        <Grid item xs={6}>
          <TextField
            fullWidth
            label="License Number"
            name="licenseNumber"
            value={form.licenseNumber}
            onChange={handleChange}
          />
        </Grid>
        <Grid item xs={6}>
          <Button variant="outlined" component="label" fullWidth>
            Upload License Image
            <input
              type="file"
              name="licenseImage"
              hidden
              onChange={handleFileChange}
            />
          </Button>
          <Button
            variant="contained"
            color="secondary"
            sx={{ mt: 1 }}
            fullWidth
          >
            Use Camera
          </Button>
        </Grid>
      </Grid>

      {/* RC */}
      <Grid container spacing={2} alignItems="center" sx={{ mb: 2 }}>
        <Grid item xs={6}>
          <TextField
            fullWidth
            label="RC Number"
            name="rcNumber"
            value={form.rcNumber}
            onChange={handleChange}
          />
        </Grid>
        <Grid item xs={6}>
          <Button variant="outlined" component="label" fullWidth>
            Upload RC Image
            <input
              type="file"
              name="rcImage"
              hidden
              onChange={handleFileChange}
            />
          </Button>
          <Button
            variant="contained"
            color="secondary"
            sx={{ mt: 1 }}
            fullWidth
          >
            Use Camera
          </Button>
        </Grid>
      </Grid>

      {/* Insurance */}
      <Grid container spacing={2} alignItems="center" sx={{ mb: 2 }}>
        <Grid item xs={6}>
          <TextField
            fullWidth
            label="Insurance Policy Number"
            name="insuranceNumber"
            value={form.insuranceNumber}
            onChange={handleChange}
          />
        </Grid>
        <Grid item xs={6}>
          <Button variant="outlined" component="label" fullWidth>
            Upload Insurance Image
            <input
              type="file"
              name="insuranceImage"
              hidden
              onChange={handleFileChange}
            />
          </Button>
          <Button
            variant="contained"
            color="secondary"
            sx={{ mt: 1 }}
            fullWidth
          >
            Use Camera
          </Button>
        </Grid>
      </Grid>

      {/* Aadhar Front */}
      <Grid container spacing={2} alignItems="center" sx={{ mb: 2 }}>
        <Grid item xs={6}>
          <Typography>Aadhar Card (Front)</Typography>
        </Grid>
        <Grid item xs={6}>
          <Button variant="outlined" component="label" fullWidth>
            Upload Aadhar Front
            <input
              type="file"
              name="aadharFront"
              hidden
              onChange={handleFileChange}
            />
          </Button>
          <Button
            variant="contained"
            color="secondary"
            sx={{ mt: 1 }}
            fullWidth
          >
            Use Camera
          </Button>
        </Grid>
      </Grid>

      {/* Aadhar Back */}
      <Grid container spacing={2} alignItems="center" sx={{ mb: 2 }}>
        <Grid item xs={6}>
          <Typography>Aadhar Card (Back)</Typography>
        </Grid>
        <Grid item xs={6}>
          <Button variant="outlined" component="label" fullWidth>
            Upload Aadhar Back
            <input
              type="file"
              name="aadharBack"
              hidden
              onChange={handleFileChange}
            />
          </Button>
          <Button
            variant="contained"
            color="secondary"
            sx={{ mt: 1 }}
            fullWidth
          >
            Use Camera
          </Button>
        </Grid>
      </Grid>

      {/* Submit */}
      <Button
        variant="contained"
        sx={{ bgcolor: "black", color: "white", mt: 3 }}
        fullWidth
        onClick={handleSubmit}
      >
        Submit Documents
      </Button>
    </Box>
  );
}
